(function(){
  var PHRASES=['Subscribe to enjoy this recipe','Subscribe now','Cancel anytime','unlimited access','last free recipe','Update payment','access will expire','Resubscribe to enjoy','Delicious recipes for everyday','New recipe suggestions from our editors'];
  function findKillTarget(el){
    var t=el;
    while(t.parentElement && t.parentElement!==document.body){
      var txt=(t.parentElement.textContent||'').replace(/\s+/g,' ').trim();
      var hasOtherContent=Array.from(t.parentElement.children).some(function(c){
        return c!==t && c.textContent.trim().length>100 && !PHRASES.some(function(p){return c.textContent.includes(p);});
      });
      if(hasOtherContent) break;
      t=t.parentElement;
    }
    return t;
  }
  function kill(){
    document.querySelectorAll('div,section,aside').forEach(function(el){
      if(el.dataset.gremlinKilled) return;
      var txt=el.textContent||'';
      if(txt.length>2000) return;
      if(PHRASES.some(function(p){return txt.includes(p);})){
        var target=findKillTarget(el);
        target.style.cssText='display:none!important';
        target.dataset.gremlinKilled='1';
      }
    });
    document.body.style.overflow='';
    document.documentElement.style.overflow='';
    document.querySelectorAll('[style*="filter"]').forEach(function(el){
      if(el.style.filter && el.style.filter.includes('blur')) el.style.filter='none';
    });
    // Reveal anything with mask-image (fade-out gradients)
    document.querySelectorAll('[style*="mask"]').forEach(function(el){
      el.style.maskImage='none'; el.style.webkitMaskImage='none';
    });
  }
  kill();
  var obs=new MutationObserver(function(){kill();});
  obs.observe(document.body,{childList:true,subtree:true});
  setTimeout(function(){obs.disconnect();},20000);
})();
